const eventsByFilters = `-- name: EventsByFilters :many
SELECT a.id,
       a.entity_id::text AS entity_id,
       a.occurred_at     AS timestamp,
       a.change_kind,
       a.entity_type,
       a.actor,
       p.slug            AS project,
       a.entity_title    AS title,
       a.payload         AS metadata,
       a.created_at
FROM activity_events a
LEFT JOIN projects p ON p.id = a.project_id
WHERE a.occurred_at >= $1 AND a.occurred_at < $2
  AND ($3::text IS NULL OR a.entity_type = $3)
  AND ($4::text IS NULL OR p.slug = $4)
  AND ($5::text[] IS NULL OR a.actor = ANY($5::text[]))
ORDER BY a.occurred_at DESC
LIMIT $6
`

type EventsByFiltersParams struct {
	StartTime        time.Time `json:"start_time"`
	EndTime          time.Time `json:"end_time"`
	FilterEntityType *string   `json:"filter_entity_type"`
	FilterProject    *string   `json:"filter_project"`
	FilterActors     []string  `json:"filter_actors"`
	MaxResults       int32     `json:"max_results"`
}

type EventsByFiltersRow struct {
	ID         uuid.UUID       `json:"id"`
	EntityID   string          `json:"entity_id"`
	Timestamp  time.Time       `json:"timestamp"`
	ChangeKind string          `json:"change_kind"`
	EntityType string          `json:"entity_type"`
	Actor      string          `json:"actor"`
	Project    *string         `json:"project"`
	Title      *string         `json:"title"`
	Metadata   json.RawMessage `json:"metadata"`
	CreatedAt  time.Time       `json:"created_at"`
}

// List activity events within a time range with optional entity_type, project,
// and actor filters. entity_type matches activity_events.entity_type; project
// matches the joined projects.slug; actors is a multi-value allowlist matching
// activity_events.actor (NULL/empty → all actors). actor projection mirrors
// EventsByTimeRange.
func (q *Queries) EventsByFilters(ctx context.Context, arg EventsByFiltersParams) ([]EventsByFiltersRow, error) {
	rows, err := q.db.Query(ctx, eventsByFilters,
		arg.StartTime,
		arg.EndTime,
		arg.FilterEntityType,
		arg.FilterProject,
		arg.FilterActors,
		arg.MaxResults,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []EventsByFiltersRow{}
	for rows.Next() {
		var i EventsByFiltersRow
		if err := rows.Scan(
			&i.ID,
			&i.EntityID,
			&i.Timestamp,
			&i.ChangeKind,
			&i.EntityType,
			&i.Actor,
			&i.Project,
			&i.Title,
			&i.Metadata,
			&i.CreatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

